using Microsoft.ML;
using Microsoft.ML.Data;

var builder = WebApplication.CreateBuilder(args);
var app = builder.Build();

// --- Data classes ---

public class CustomerData
{
    [LoadColumn(0)] public float Age { get; set; }
    [LoadColumn(1)] public float Income { get; set; }
    [LoadColumn(2)] public string Region { get; set; } = string.Empty;
    [LoadColumn(3)] public float PurchaseHistory { get; set; }
    [LoadColumn(4)] [ColumnName("LabelText")] public string Churned { get; set; } = string.Empty;
}

public class ChurnPrediction
{
    [ColumnName("PredictedLabel")] public bool PredictedLabel { get; set; }
    public float Probability { get; set; }
    public float Score { get; set; }
}

// --- Train the model ---

var mlContext = new MLContext(seed: 42);

var csvPath = Path.Combine(AppContext.BaseDirectory, "..", "..", "..", "Data", "customers.csv");
if (!File.Exists(csvPath))
    csvPath = Path.Combine(Directory.GetCurrentDirectory(), "Data", "customers.csv");

var dataView = mlContext.Data.LoadFromTextFile<CustomerData>(csvPath, hasHeader: true, separatorChar: ',');

var pipeline = mlContext.Transforms.CustomMapping<CustomerData, LabelMapping>(
        (input, output) => output.Label = string.Equals(input.Churned, "Yes", StringComparison.OrdinalIgnoreCase),
        contractName: "ChurnLabelMapping")
    .Append(mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", "Region"))
    .Append(mlContext.Transforms.Concatenate("Features", "Age", "Income", "PurchaseHistory", "RegionEncoded"))
    .Append(mlContext.Transforms.NormalizeMinMax("Features"))
    .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression(
        labelColumnName: "Label", featureColumnName: "Features"));

var model = pipeline.Fit(dataView);

// --- Evaluate ---

var predictions = model.Transform(dataView);
var metrics = mlContext.BinaryClassification.Evaluate(predictions, labelColumnName: "Label");
Console.WriteLine($"Model trained — Accuracy: {metrics.Accuracy:P2}, AUC: {metrics.AreaUnderRocCurve:P2}, F1: {metrics.F1Score:P2}");

var predictionEngine = mlContext.Model.CreatePredictionEngine<CustomerData, ChurnPrediction>(model);

// --- Endpoints ---

app.MapGet("/", () => new
{
    accuracy = metrics.Accuracy,
    auc = metrics.AreaUnderRocCurve,
    f1 = metrics.F1Score
});

app.MapPost("/predict", (CustomerPredictRequest req) =>
{
    var input = new CustomerData
    {
        Age = req.Age,
        Income = req.Income,
        Region = req.Region,
        PurchaseHistory = req.PurchaseHistory,
        Churned = "" // not known at prediction time
    };
    var result = predictionEngine.Predict(input);
    return new
    {
        willChurn = result.PredictedLabel,
        probability = result.Probability,
        score = result.Score
    };
});

app.Run();

public record CustomerPredictRequest(float Age, float Income, string Region, float PurchaseHistory);

public class LabelMapping
{
    public bool Label { get; set; }
}

